@page "/account/login"
@using Microsoft.AspNetCore.Identity
@using System.ComponentModel.DataAnnotations

@attribute [ExcludeFromInteractiveRouting]

<PageTitle>Log in</PageTitle>

<div class="row justify-content-center">
    <div class="col-md-4">
        <h1>Log in</h1>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger" role="alert">@errorMessage</div>
        }

        <EditForm Model="Input" method="post" OnValidSubmit="LoginUser" FormName="login">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" role="alert" />

            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText @bind-Value="Input.Email" id="email" class="form-control" autocomplete="username" placeholder="name@example.com" />
                <ValidationMessage For="() => Input.Email" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText type="password" @bind-Value="Input.Password" id="password" class="form-control" autocomplete="current-password" placeholder="password" />
                <ValidationMessage For="() => Input.Password" class="text-danger" />
            </div>

            <div class="mb-3 form-check">
                <InputCheckbox @bind-Value="Input.RememberMe" id="rememberMe" class="form-check-input" />
                <label for="rememberMe" class="form-check-label">Remember me</label>
            </div>

            <button type="submit" class="w-100 btn btn-lg btn-primary">Log in</button>
        </EditForm>

        <div class="mt-3">
            <p><a href="/account/register">Register as a new user</a></p>
        </div>
    </div>
</div>

@code {
    private string? errorMessage;

    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;

    [SupplyParameterFromForm]
    private LoginInput Input { get; set; } = new();

    private async Task LoginUser()
    {
        var signInManager = HttpContext.RequestServices.GetRequiredService<SignInManager<IdentityUser>>();

        var result = await signInManager.PasswordSignInAsync(
            Input.Email!, Input.Password!, Input.RememberMe, lockoutOnFailure: false);

        if (result.Succeeded)
        {
            NavigationManager.NavigateTo("/", forceLoad: true);
        }
        else
        {
            errorMessage = "Error: Invalid login attempt.";
        }
    }

    [Inject]
    private NavigationManager NavigationManager { get; set; } = default!;

    private sealed class LoginInput
    {
        [Required]
        [EmailAddress]
        public string? Email { get; set; }

        [Required]
        [DataType(DataType.Password)]
        public string? Password { get; set; }

        public bool RememberMe { get; set; }
    }
}

